firmware_template.source:
#include "neopixel.h"
#define NUM_LEDS 30
#define LED_PIN 16
static Adafruit_NeoPixel strip(NUM_LEDS,LED_PIN,NEO_GRB+NEO_KHZ800);
void neopixel_setup(){strip.begin();strip.setBrightness(50);strip.show();Serial.println("[neo] OK");}
void neopixel_loop(){}
void neopixel_set(uint16_t i,uint8_t r,uint8_t g,uint8_t b){strip.setPixelColor(i,strip.Color(r,g,b));strip.show();}
void neopixel_fill(uint8_t r,uint8_t g,uint8_t b){strip.fill(strip.Color(r,g,b));strip.show();}
void neopixel_clear(){strip.clear();strip.show();}
void neopixel_set_brightness(uint8_t b){strip.setBrightness(b);strip.show();}
